import {{ Injectable }} from '@nestjs/common';
import {{ CacheService }} from './models/cache.model';
import {{ CacheServiceRepository }} from './repositories/cache.repository';

@Injectable()
export class CacheServiceService {{
  constructor(
    private readonly repository: CacheServiceRepository,
  ) {{}}

  async findAll(): Promise<CacheService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<CacheService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<CacheService>): Promise<CacheService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<CacheService>): Promise<CacheService> {{
    return this.repository.update(id, data);
  }}
}}
